-- =============================================================================
-- POLESTAR 테스트 데이터 정리 스크립트 (PostgreSQL 버전)
-- 파일: testdata/pg/99_cleanup.sql
-- 설명: 테스트 데이터 삭제 후 테이블 DROP
-- 주의: 이 스크립트는 테스트 데이터를 포함한 모든 데이터를 삭제합니다.
-- DB 엔진: PostgreSQL 14+
-- 원본: testdata/99_cleanup.sql (IBM DB2)
-- =============================================================================

-- -----------------------------------------------------------------------------
-- 1. 테스트 데이터만 삭제 (기존 데이터가 있을 경우 안전하게 범위 지정)
-- -----------------------------------------------------------------------------
-- CMM_RESOURCE: ID 300001 이상 테스트 데이터만 삭제
DELETE FROM polestar.cmm_resource WHERE id >= 300001;

-- CORE_CONFIG_PROP: ID 500001 이상 테스트 데이터만 삭제
DELETE FROM polestar.core_config_prop WHERE id >= 500001;

-- -----------------------------------------------------------------------------
-- 2. 테이블 DROP (전체 환경 제거 시)
-- 주의: 아래 DROP 문은 기존 데이터를 포함한 테이블 전체를 삭제합니다.
--       테스트 데이터만 삭제하려면 위의 DELETE 문만 실행하세요.
-- -----------------------------------------------------------------------------
-- DROP TABLE polestar.core_config_prop;
-- DROP TABLE polestar.cmm_resource;
-- DROP SCHEMA polestar CASCADE;
